function display(msg) {
    if (msg === null || msg === undefined) {
        console.log("Empty");
    } else {
        console.log(msg);
    }
}

examples.toCode:
fn display(msg: Option<&str>) {
    match msg {
        Some(text) => println!("{}", text),
        None => println!("Empty"),
    }
}

examples.fromCode:
function divide(a, b) {
    if (b === 0) throw new Error("Zero division");
    return a / b;
}

examples.toCode:
fn divide(a: f64, b: f64) -> Result<f64, &'static str> {
    if b == 0.0 {
        Err("Zero division")
    } else {
        Ok(a / b)
    }
}
